import os
import sys

class SimpleShell:
    def __init__(self):
        self.commands = {
            'ls': self.cmd_ls,
            'pwd': self.cmd_pwd,
            'cd': self.cmd_cd,
            'echo': self.cmd_echo,
            'exit': self.cmd_exit
        }

    def run(self):
        """Main shell loop"""
        while True:
            try:
                # Display prompt
                cwd = os.getcwd()
                user = os.environ.get('USER', 'user')
                prompt = f"{user}@{os.uname().nodename}:{cwd}$ "

                # Read command input
                command_line = input(prompt).strip()

                # Parse command
                if not command_line:
                    continue

                parts = command_line.split()
                cmd = parts[0]
                args = parts[1:]

                # Execute command
                if cmd in self.commands:
                    self.commands[cmd](args)
                else:
                    print(f"Command not found: {cmd}")

            except EOFError:
                break
            except KeyboardInterrupt:
                print("\nUse 'exit' to quit")

    def cmd_ls(self, args):
        """List directory contents - wraps system call"""
        path = args[0] if args else '.'
        try:
            files = os.listdir(path)
            for f in files:
                print(f)
        except FileNotFoundError:
            print(f"ls: cannot access '{path}'")

    def cmd_pwd(self, args):
        """Print working directory"""
        print(os.getcwd())

    def cmd_cd(self, args):
        """Change directory - wraps system call"""
        if not args:
            os.chdir(os.environ.get('HOME', '/'))
        else:
            try:
                os.chdir(args[0])
            except FileNotFoundError:
                print(f"cd: {args[0]}: No such file or directory")

    def cmd_echo(self, args):
        """Display text"""
        print(' '.join(args))

    def cmd_exit(self, args):
        """Exit shell"""
        sys.exit(0)

# Main entry point
if __name__ == '__main__':
    shell = SimpleShell()
    shell.run()

