int main() {
    pid_t pid;
    int x = 10;

    printf("Before fork: x = %d\n", x);

    // FORK SYSTEM CALL - creates new process
    pid = fork();

    if (pid < 0) {
        // Fork failed
        fprintf(stderr, "Fork failed!\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process execution
        printf("CHILD: My PID is %d\n", getpid());
        printf("CHILD: Parent PID is %d\n", getppid());
        x = 20;
        printf("CHILD: Modified x = %d\n", x);

        // Execute another program
        // execlp("ls", "ls", "-l", NULL);
    }
    else {
        // Parent process execution
        printf("PARENT: My PID is %d\n", getpid());
        printf("PARENT: Child PID is %d\n", pid);

        // Wait for child to complete
        wait(NULL);
        printf("PARENT: Child completed\n");
        printf("PARENT: Original x = %d\n", x);
    }

    return 0;
}

/*
 * EXPLANATION OF FORK() SYSTEM CALL:
 * 
 * 1. fork() creates an exact copy of the calling process
 * 2. Returns twice: once in parent (with child's PID)
 *                   once in child (with value 0)
 * 3. Child gets copy of parent's address space
 * 4. Both processes continue execution after fork()
 * 5. This demonstrates OS process management
